import { useEffect, useRef, useState } from 'react';

export function SparklesBackground({
  id = "sparkles",
  background = "transparent",
  minSize = 0.6,
  maxSize = 1.8,
  particleDensity = 100,
  particleColor = "#FFF",
  className = ""
}) {
  const canvasRef = useRef(null);
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });

  useEffect(() => {
    if (typeof window === "undefined") return;
    const handleResize = () => {
      if (canvasRef.current) {
        const parent = canvasRef.current.parentElement;
        if (parent) {
          setDimensions({
            width: parent.clientWidth,
            height: parent.clientHeight
          });
        }
      }
    };
    handleResize();
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas || dimensions.width === 0) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let animationFrameId;
    const particles = [];

    class Particle {
      constructor(w, h) {
        this.x = Math.random() * w;
        this.y = Math.random() * h;
        this.size = Math.random() * (maxSize - minSize) + minSize;
        this.speedY = Math.random() * 0.5 + 0.1;
        this.opacity = Math.random();
        this.fadeSpeed = Math.random() * 0.02 + 0.005;
        this.direction = Math.random() > 0.5 ? 1 : -1;
      }
      update(w, h) {
        this.y -= this.speedY;
        if (this.y < 0) this.y = h;
        this.opacity += this.fadeSpeed * this.direction;
        if (this.opacity > 1 || this.opacity < 0) {
          this.direction = -this.direction;
        }
      }
      draw(c) {
        c.fillStyle = particleColor;
        c.globalAlpha = Math.max(0, Math.min(1, this.opacity));
        c.beginPath();
        c.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        c.fill();
      }
    }

    const particleCount = Math.floor((dimensions.width * dimensions.height) / (10000 / particleDensity) * 0.1);
    for (let i = 0; i < particleCount; i++) {
      particles.push(new Particle(dimensions.width, dimensions.height));
    }

    const animate = () => {
      ctx.clearRect(0, 0, dimensions.width, dimensions.height);
      particles.forEach((p) => {
        p.update(dimensions.width, dimensions.height);
        p.draw(ctx);
      });
      animationFrameId = requestAnimationFrame(animate);
    };
    animate();

    return () => {
      cancelAnimationFrame(animationFrameId);
    };
  }, [dimensions, minSize, maxSize, particleDensity, particleColor]);

  return (
    <canvas
      ref={canvasRef}
      id={id}
      width={dimensions.width}
      height={dimensions.height}
      style={{ background }}
      className={`pointer-events-none block w-full h-full ${className}`}
    />
  );
}

import { useRef, useState } from 'react';

export function MagnifiedDock({ items = [] }) {
  const [hoveredIndex, setHoveredIndex] = useState(null);
  const dockRef = useRef(null);

  const getScale = (index) => {
    if (hoveredIndex === null) return 1;
    const dist = Math.abs(index - hoveredIndex);
    if (dist === 0) return 1.5;
    if (dist === 1) return 1.25;
    if (dist === 2) return 1.1;
    return 1;
  };

  return (
    <div className="flex items-center justify-center py-10">
      <div 
        ref={dockRef}
        onMouseLeave={() => setHoveredIndex(null)}
        className="flex items-end gap-4 rounded-3xl border border-white/10 bg-neutral-900/80 px-4 pb-3 pt-4 backdrop-blur-md shadow-2xl"
      >
        {items.map((item, idx) => {
          const scale = getScale(idx);
          return (
            <button
              key={idx}
              onMouseEnter={() => setHoveredIndex(idx)}
              style={{
                transform: `scale(${scale})`,
                transition: 'transform 0.15s cubic-bezier(0.2, 0.8, 0.2, 1)',
                transformOrigin: 'bottom center'
              }}
              className="flex h-12 w-12 items-center justify-center rounded-2xl bg-neutral-800 text-white shadow-md hover:bg-neutral-700 transition-colors"
              aria-label={item.label || `Dock Item ${idx + 1}`}
            >
              {item.icon}
            </button>
          );
        })}
      </div>
    </div>
  );
}

import { useEffect, useRef, useState } from 'react';

export function TextReveal({ 
  text = "Experience modern animation patterns built for speeds.", 
  className = ""
}) {
  const containerRef = useRef(null);
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
          observer.unobserve(entry.target);
        }
      },
      { threshold: 0.1 }
    );
    if (containerRef.current) {
      observer.observe(containerRef.current);
    }
    return () => {
      if (containerRef.current) {
        observer.disconnect();
      }
    };
  }, []);

  const words = text.split(" ");

  return (
    <p 
      ref={containerRef} 
      className={`flex flex-wrap text-2xl font-semibold tracking-tight text-foreground ${className}`}
    >
      {words.map((word, idx) => (
        <span 
          key={idx} 
          style={{
            opacity: isVisible ? 1 : 0,
            transform: isVisible ? 'translateY(0)' : 'translateY(12px)',
            transition: `opacity 0.5s ease-out ${idx * 0.08}s, transform 0.5s cubic-bezier(0.16, 1, 0.3, 1) ${idx * 0.08}s`,
            display: 'inline-block'
          }}
          className="mr-2.5 mb-1.5"
        >
          {word}
        </span>
      ))}
    </p>
  );
}

