import { useEffect, useRef, useState } from 'react';

export function ResizablePanel({ children, className = "" }) {
  const containerRef = useRef(null);
  const [height, setHeight] = useState('auto');

  useEffect(() => {
    if (!containerRef.current) return;
    const resizeObserver = new ResizeObserver((entries) => {
      for (let entry of entries) {
        setHeight(entry.contentRect.height);
      }
    });

    // Observe the single inner child wrapper
    const innerWrapper = containerRef.current.firstChild;
    if (innerWrapper) {
      resizeObserver.observe(innerWrapper);
    }

    return () => resizeObserver.disconnect();
  }, [children]);

  return (
    <div 
      ref={containerRef}
      style={{
        height: height === 'auto' ? 'auto' : `${height}px`,
        transition: 'height 0.25s cubic-bezier(0.25, 1, 0.5, 1)'
      }}
      className={`overflow-hidden relative ${className}`}
    >
      <div>{children}</div>
    </div>
  );
}

import { useRef, useState } from 'react';

export function MagneticHover({ children, range = 35, className = "" }) {
  const ref = useRef(null);
  const [position, setPosition] = useState({ x: 0, y: 0 });

  const handleMouseMove = (e) => {
    if (!ref.current) return;
    const { clientX, clientY } = e;
    const { left, top, width, height } = ref.current.getBoundingClientRect();
    const centerX = left + width / 2;
    const centerY = top + height / 2;

    const distanceX = clientX - centerX;
    const distanceY = clientY - centerY;

    // Calculate relative distance within range threshold
    const distance = Math.hypot(distanceX, distanceY);
    if (distance < range) {
      setPosition({ x: distanceX * 0.35, y: distanceY * 0.35 });
    } else {
      setPosition({ x: 0, y: 0 });
    }
  };

  const handleMouseLeave = () => {
    setPosition({ x: 0, y: 0 });
  };

  return (
    <div
      ref={ref}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      style={{
        transform: `translate3d(${position.x}px, ${position.y}px, 0)`,
        transition: 'transform 0.15s cubic-bezier(0.25, 1, 0.5, 1)'
      }}
      className={`inline-block ${className}`}
    >
      {children}
    </div>
  );
}
